#include <stdio.h>
#include <stdlib.h>
#define MAXN 200005
int parent[MAXN], rank[MAXN];
int find(int x) { return parent[x] == x ? x : (parent[x] = find(parent[x])); }
void unionSet(int x, int y) { int rootx = find(x), rooty = find(y); if (rootx != rooty) { if (rank[rootx] > rank[rooty]) { parent[rooty] = rootx; } else if (rank[rootx] < rank[rooty]) { parent[rootx] = rooty; } else { parent[rooty] = rootx; rank[rootx]++; } } }
int main() {
    int N, E;
    scanf("%d %d", &N, &E);
    for (int i = 1; i <= N; i++) {
        scanf("%d", &parent[i]);
        rank[i] = 0;
    }
    for (int i = 0; i < E; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        unionSet(x, y);
    }
    for (int i = 1; i <= N; i++) {
        int count = 0;
        for (int j = 1; j <= N; j++) {
            if (find(i) != find(j) && parent[i] == parent[j]) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

