parent = [0] * MAXN
rank = [0] * MAXN
def find(x):
    if parent[x] == x:
        return x
    parent[x] = find(parent[x])
    return parent[x]
def unionSet(x, y):
    rootx = find(x)
    rooty = find(y)
    if rootx != rooty:
        if rank[rootx] > rank[rooty]:
            parent[rooty] = rootx
        elif rank[rootx] < rank[rooty]:
            parent[rootx] = rooty
        else:
            parent[rooty] = rootx
            rank[rootx] += 1
N, E = map(int, sys.stdin.readline().split())
for i in range(1, N + 1):
    parent[i] = int(sys.stdin.readline())
    rank[i] = 0
for _ in range(E):
    x, y = map(int, sys.stdin.readline().split())
    unionSet(x, y)
